import{c as i,Q as t,j as a,m as n}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Gemini相关问题","description":"","frontmatter":{},"headers":[],"relativePath":"faq/Gemini.md","filePath":"faq/Gemini.md","lastUpdated":1779875536000}'),o={name:"faq/Gemini.md"};function r(l,e,d,s,p,c){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="gemini相关问题" tabindex="-1">Gemini相关问题 <a class="header-anchor" href="#gemini相关问题" aria-label="Permalink to &quot;Gemini相关问题&quot;">​</a></h1><hr><ul><li><a href="/faq/Gemini.html">Gemini CLI 使用难题与建议</a></li><li><a href="/faq/Gemini.html">如何在 Cline 使用 Gemini-3</a></li></ul><h3 id="gemini-cli-使用难题与建议" tabindex="-1">Gemini CLI 使用难题与建议 <a class="header-anchor" href="#gemini-cli-使用难题与建议" aria-label="Permalink to &quot;Gemini CLI 使用难题与建议&quot;">​</a></h3><p>现状说明</p><p>Gemini CLI 目前存在多种使用问题，例如可能无法正常调用模型、无法粘贴图片。<br> 因此通常不建议将 Gemini-3 接入 Gemini CLI。</p><p>更推荐的方式</p><ul><li>优先使用 Roo Code 等第三方 VSCode 插件</li><li>如必须使用 Gemini CLI，建议使用 Antigravity 分组渠道（兼容性更好）</li></ul><p><img src="https://docs.packyapi.com/assets/image/FAQ/Gemini/001.webp" alt=""></p><p>重要</p><p>如果你不会使用 Roo Code，我们推荐你使用 Antigravity 分组渠道的模型在 Gemini CLI 使用，能比较好地适配 CLI。特别提醒：该分组的 Gemini-3 模型名称可能与其他分组不同，详情查看 <a href="/token/2-group.html">Antigravity 分组说明</a> 内容，避免配置时出现“无可用渠道”或“模型不存在”问题。</p><p>特别提醒</p><ul><li>在 Roo Code 等第三方使用时，选取 <code>OpenAI Response</code> 请求格式</li><li>Antigravity 分组的模型通常不自带联网功能，可能需要借助 MCP 等工具实现</li></ul><h3 id="如何在-cline-使用-gemini-3" tabindex="-1">如何在 Cline 使用 Gemini-3 <a class="header-anchor" href="#如何在-cline-使用-gemini-3" aria-label="Permalink to &quot;如何在 Cline 使用 Gemini-3&quot;">​</a></h3><h4 id="软件要求" tabindex="-1">软件要求 <a class="header-anchor" href="#软件要求" aria-label="Permalink to &quot;软件要求&quot;">​</a></h4><table tabindex="0"><thead><tr><th>软件</th><th>版本要求</th><th>下载链接</th></tr></thead><tbody><tr><td><strong>VSCode</strong></td><td>1.80.0+</td><td><a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">下载 VSCode</a></td></tr></tbody></table><h4 id="_1-创建-gemini-分组密钥" tabindex="-1">1. 创建 Gemini 分组密钥 <a class="header-anchor" href="#_1-创建-gemini-分组密钥" aria-label="Permalink to &quot;1\\. 创建 Gemini 分组密钥&quot;">​</a></h4><p>按照 <a href="/register/4-token.html">创建 API 令牌</a> 一章提到的方法，创建如下图中 <code>gemini</code> 分组的 API 密钥：</p><p><img src="https://docs.packyapi.com/assets/image/FAQ/Gemini/002.webp" alt="创建 API 选择分组示意图">创建 API 选择分组示意图</p><h4 id="_2-安装-cline-插件" tabindex="-1">2. 安装 Cline 插件 <a class="header-anchor" href="#_2-安装-cline-插件" aria-label="Permalink to &quot;2\\. 安装 Cline 插件&quot;">​</a></h4><ul><li>打开 VSCode</li><li>单击左侧边栏的 <strong>扩展</strong> 图标（或按 <code>Ctrl+Shift+X</code> / <code>Cmd+Shift+X</code>）</li><li>在搜索框输入 <strong>Cline</strong></li><li>找到 Cline 插件，单击 <strong>安装</strong></li></ul><p>安装提示</p><ul><li>安装完成后，左侧边栏会出现 Cline 图标</li><li>首次使用需要配置 API Key</li><li>建议安装最新版本以获得最佳体验</li></ul><h4 id="_3-打开-cline-界面" tabindex="-1">3. 打开 Cline 界面 <a class="header-anchor" href="#_3-打开-cline-界面" aria-label="Permalink to &quot;3\\. 打开 Cline 界面&quot;">​</a></h4><p>安装完成后，有两种方式打开 Cline：</p><p><strong>方式一：侧边栏图标</strong></p><ul><li>单击 VSCode 左侧边栏的 Cline 图标</li></ul><p><strong>方式二：命令面板</strong></p><ul><li>按 <code>Ctrl+Shift+P</code> (Windows/Linux) 或 <code>Cmd+Shift+P</code> (macOS)</li><li>输入 <code>Cline: Open</code></li><li>按 Enter</li></ul><h4 id="_4-首次配置" tabindex="-1">4. 首次配置 <a class="header-anchor" href="#_4-首次配置" aria-label="Permalink to &quot;4\\. 首次配置&quot;">​</a></h4><p>打开 Cline 界面后，按以下步骤配置：</p><ol><li>单击 <strong>API Configuration</strong> 按钮</li><li>按下方填写配置信息</li></ol><pre><code>API Provider: OpenAI-compatible
Base URL: https://api.suirenai.com/v1
API Key: sk-*****
Model ID: gemini-3-pro-preview
</code></pre><p><img src="https://docs.packyapi.com/assets/image/FAQ/Gemini/003.webp" alt="Cline 配置界面示意图">Cline 配置界面示意图</p><p>安全提醒</p><p>请妥善保管你的 <code>API Key</code>，不要在群聊或公开截图中泄露。</p><p>已有用户提示</p><p>如果您之前使用过 Cline，请单击右上角的 <strong>⚙️ 设置</strong> 按钮进入配置界面。</p><p><strong>配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>推荐值</th><th>说明</th></tr></thead><tbody><tr><td><strong>API Provider</strong></td><td><code>OpenAI-compatible</code></td><td>推荐选择此项，支持更多模型</td></tr><tr><td><strong>Base URL</strong></td><td><code>https://api.suirenai.com/v1</code></td><td>Suirenai 的兼容端点</td></tr><tr><td><strong>API Key</strong></td><td><code>sk-******</code></td><td>您的 Suirenai Key</td></tr><tr><td><strong>Model ID</strong></td><td><code>gemini-3-pro-preview</code></td><td>推荐使用代码专精模型</td></tr></tbody></table><h4 id="_5-完成配置" tabindex="-1">5. 完成配置 <a class="header-anchor" href="#_5-完成配置" aria-label="Permalink to &quot;5\\. 完成配置&quot;">​</a></h4><p>单击右上角 <strong>Done</strong> 。</p>`,42)])])}const g=i(o,[["render",r]]);export{m as __pageData,g as default};
